#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10,mod=1e9+7;

struct Node{
    int l,r;
	mutable int v;
    bool operator<(const Node &x) const{return l<x.l;}
};

int n,m,a[N];
set<Node> odt;

auto Split(int x){
    auto it=odt.lower_bound(Node{x,0,0});
    if(it!=odt.end() && it->l==x) return it;
    --it;
    int l=it->l,r=it->r,v=it->v;
    odt.erase(it),odt.insert(Node{l,x-1,v});
    return odt.insert(Node{x,r,v}).first;
}

int Query(int l,int r){
    if(l>r) swap(l,r);
    int res=0;
    auto itl=Split(l),itr=Split(r+1);
    for(;itl!=itr;itl++)
        res=(res+1ll*itl->v*(itl->r-itl->l+1))%mod;
    return res;
}

void Assign(int l,int r,int val){
    if(l>r) swap(l,r);
	auto itl=Split(l),itr=Split(r+1);
	odt.erase(itl,itr);
	odt.insert(Node{l,r,val});
}

void Add(int l,int r,int val){
    if(l>r) swap(l,r);
	auto itl=Split(l),itr=Split(r+1);
	for(;itl!=itr;itl++)
		itl->v=(itl->v+val)%mod; 
}

void Copy(int l,int r,int x,int y){
    if(l>r) swap(l,r),swap(x,y);
	queue<Node> q;
	auto itl=Split(l),itr=Split(r+1);
	for(;itl!=itr;itl++)
		q.push(Node{itl->l+x-l,itl->r+x-l,itl->v});
	auto itx=Split(x),ity=Split(y+1);
	odt.erase(itx,ity);
    while(q.size()){
        odt.insert(q.front());
        q.pop();
    }
}

void Swap(int l,int r,int x,int y){
    if(l>r) swap(l,r),swap(x,y);
	queue<Node> q;
	auto itl=Split(l),itr=Split(r+1);
	for(auto it=itl;it!=itr;it++)
		q.push(Node{it->l+x-l,it->r+x-l,it->v});
	auto itx=Split(x),ity=Split(y+1);
	for(auto it=itx;it!=ity;it++)
		q.push(Node{it->l+l-x,it->r+l-x,it->v});
	odt.erase(itl,itr);
	odt.erase(itx,ity);
	while(!q.empty()){
		odt.insert(q.front());
		q.pop();
	}
} 

void Reverse(int l,int r){
    if(l>r) swap(l,r);
	auto itl=Split(l),itr=Split(r+1);
	queue<Node> q;
	for(auto it=itl;it!=itr;it++)
		q.push(*it);
	odt.erase(itl,itr);
	while(!q.empty()){
		auto x=q.front();
		odt.insert(Node{l+r-x.r,l+r-x.l,x.v});
		q.pop();
	}
}

void Perform(){
	for(auto it:odt)
		for(;it.l<=min(n,it.r);it.l++)
			printf("%d ",it.v);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        odt.insert(Node{i,i,a[i]});
    }
    odt.insert(Node{n+1,n+1,0});
    while(m--){
        int op;
        scanf("%d",&op);
        if(op==1){
            int l,r;
            scanf("%d%d",&l,&r);
            printf("%d\n",Query(l,r));
        }else if(op==2){
            int l,r,val;
            scanf("%d%d%d",&l,&r,&val);
            Assign(l,r,val);
        }else if(op==3){
            int l,r,val;
            scanf("%d%d%d",&l,&r,&val);
            Add(l,r,val);
        }else if(op==4){
            int l,r,x,y;
            scanf("%d%d%d%d",&l,&r,&x,&y);
            Copy(l,r,x,y);
        }else if(op==5){
            int l,r,x,y;
            scanf("%d%d%d%d",&l,&r,&x,&y);
            Swap(l,r,x,y);
        }else{
            int l,r;
            scanf("%d%d",&l,&r);
            Reverse(l,r);
        }
    }
    //Perform(); 
    return 0;
}
